import React, { useState, useEffect } from "react";
import axios from "axios";
import { motion } from "framer-motion";
import { Trophy, Plus, Trash2, Pencil } from "lucide-react";

const API = "http://127.0.0.1:8001/api";

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState("");

  const [stats, setStats] = useState(null);
  const [matches, setMatches] = useState([]);

  const [showForm, setShowForm] = useState(false);
  const [editingMatch, setEditingMatch] = useState(null);

  const [formData, setFormData] = useState({
    match_date: new Date().toISOString().split("T")[0],
    winner: "Yash",
    notes: ""
  });

  // LOAD DATA
  const loadData = async () => {
    const m = await axios.get(`${API}/matches`);
    const s = await axios.get(`${API}/stats`);
    setMatches(m.data);
    setStats(s.data);
  };

  useEffect(() => {
    if (isAuthenticated) loadData();
  }, [isAuthenticated]);

  useEffect(() => {
    if (localStorage.getItem("auth") === "true") {
      setIsAuthenticated(true);
    }
  }, []);

  // LOGIN
  const handleLogin = async () => {
    const res = await axios.post(`${API}/auth/login`, { password });
    if (res.data.success) {
      setIsAuthenticated(true);
      localStorage.setItem("auth", "true");
    } else {
      alert("Wrong password");
    }
  };

  // ADD / UPDATE
  const handleSubmit = async () => {
    try {
      if (editingMatch) {
        await axios.put(`${API}/matches/${editingMatch.id}`, formData);
      } else {
        await axios.post(`${API}/matches`, formData);
      }

      setShowForm(false);
      setEditingMatch(null);
      loadData();
    } catch {
      alert("Error adding match");
    }
  };

  // DELETE
  const handleDelete = async (id) => {
    if (window.confirm("Delete match?")) {
      await axios.delete(`${API}/matches/${id}`);
      loadData();
    }
  };

  // LOGIN UI
  if (!isAuthenticated) {
    return (
      <div className="h-screen flex items-center justify-center bg-gradient-to-br from-black via-purple-900 to-black">
        <motion.div
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          className="backdrop-blur-lg bg-white/10 border border-white/20 p-8 rounded-2xl text-white w-80"
        >
          <Trophy className="mx-auto mb-4" size={40} />
          <h1 className="text-xl font-bold text-center mb-4">
            Chess Tournament
          </h1>

          <input
            type="password"
            placeholder="Enter password"
            onChange={(e) => setPassword(e.target.value)}
            className="w-full p-2 rounded bg-white/20 mb-3 outline-none"
          />

          <button
            onClick={handleLogin}
            className="w-full bg-purple-600 hover:bg-purple-700 p-2 rounded"
          >
            Enter
          </button>
        </motion.div>
      </div>
    );
  }

  // DASHBOARD
  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 to-black text-white p-4">

      {/* HEADER */}
      <div className="flex justify-between items-center mb-6">
        <h1 className="flex items-center gap-2 text-xl font-bold">
          <Trophy /> Chess Battle
        </h1>

        {/* ✅ FIXED LOGOUT */}
        <button
          onClick={() => {
            localStorage.clear();
            window.location.reload();
          }}
          className="text-red-400"
        >
          Logout
        </button>
      </div>

      {/* STATS */}
      {stats && (
        <div className="grid md:grid-cols-3 gap-4 mb-6">
          <motion.div className="p-4 bg-white/10 rounded-xl backdrop-blur">
            Day {stats.current_day}/21
            <div className="mt-2 bg-gray-700 h-2 rounded">
              <div
                className="bg-blue-500 h-2 rounded"
                style={{ width: `${(stats.current_day / 21) * 100}%` }}
              />
            </div>
          </motion.div>

          <motion.div className="p-4 bg-purple-600 rounded-xl">
            Yash: {stats.yash_total_points}
          </motion.div>

          <motion.div className="p-4 bg-green-600 rounded-xl">
            Nishant: {stats.nishant_total_points}
          </motion.div>
        </div>
      )}

      {/* ADD BUTTON */}
      <button
        onClick={() => setShowForm(true)}
        className="flex items-center gap-2 bg-purple-600 px-4 py-2 rounded mb-4"
      >
        <Plus size={18} /> Add Match
      </button>

      {/* FORM */}
      {showForm && (
        <motion.div className="bg-white/10 p-4 rounded-xl mb-4 backdrop-blur">
          <input
            type="date"
            value={formData.match_date}
            onChange={(e) =>
              setFormData({ ...formData, match_date: e.target.value })
            }
            className="w-full p-2 mb-2 bg-white/20 rounded"
          />

          <select
            value={formData.winner}
            onChange={(e) =>
              setFormData({ ...formData, winner: e.target.value })
            }
            className="w-full p-2 mb-2 bg-white/20 rounded"
          >
            <option value="Yash">Yash</option>
            <option value="Nishant">Nishant</option>
            <option value="Draw">Draw</option>
          </select>

          <textarea
            placeholder="Notes"
            onChange={(e) =>
              setFormData({ ...formData, notes: e.target.value })
            }
            className="w-full p-2 mb-2 bg-white/20 rounded"
          />

          <button
            onClick={handleSubmit}
            className="bg-green-500 px-4 py-2 rounded mr-2"
          >
            Save
          </button>

          <button
            onClick={() => setShowForm(false)}
            className="border px-4 py-2 rounded"
          >
            Cancel
          </button>
        </motion.div>
      )}

      {/* MATCH LIST */}
      <div className="space-y-3">
        {matches.map((m) => (
          <motion.div
            key={m.id}
            whileHover={{ scale: 1.02 }}
            className="p-3 bg-white/10 rounded-xl flex justify-between items-center backdrop-blur"
          >
            <div>
              <p>{m.match_date}</p>
              <p className="text-sm text-gray-400">{m.notes}</p>
            </div>

            <div className="flex gap-3 items-center">
              <span
                className={`px-2 py-1 rounded ${
                  m.winner === "Yash"
                    ? "bg-purple-500"
                    : m.winner === "Nishant"
                    ? "bg-green-500"
                    : "bg-gray-500"
                }`}
              >
                {m.winner}
              </span>

              <Pencil
                size={16}
                className="cursor-pointer"
                onClick={() => {
                  setEditingMatch(m);
                  setFormData(m);
                  setShowForm(true);
                }}
              />

              <Trash2
                size={16}
                className="cursor-pointer text-red-400"
                onClick={() => handleDelete(m.id)}
              />
            </div>
          </motion.div>
        ))}
      </div>
    </div>
  );
}
